import{_ as t,o as a,c as r,ai as s,aj as n,ak as o,al as i,am as l,an as d,ao as c,ap as p,aq as h}from"./chunks/framework.lvpqbiZd.js";const S=JSON.parse('{"title":"Agent Update","description":"","frontmatter":{},"headers":[],"relativePath":"code/agent/update/index.md","filePath":"code/agent/update/index.md"}'),u={name:"code/agent/update/index.md"};function g(m,e,b,f,v,k){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="agent-update" tabindex="-1">Agent Update <a class="header-anchor" href="#agent-update" aria-label="Permalink to “Agent Update”">​</a></h1><p>Agent Update is an internal ops tool for updating the <a href="https://github.com/frappe/agent" target="_blank" rel="noreferrer">agent</a> across servers in bulk. It updates servers sequentially — triggering the update, verifying the agent comes back online, and optionally rolling back if something goes wrong — before moving to the next target.</p><p><img src="'+n+`" alt="Agent Update overview"></p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to “How It Works”">​</a></h2><ol><li>An operator creates an <strong>Agent Update</strong> document with the desired configuration (server types, restart mode, rollback settings).</li><li>On save, the server list is auto-populated from active servers matching the selected types.</li><li>The operator clicks <strong>Build Plan</strong>. This fetches the currently installed agent commit from each server and plans the update. Servers already on the target commit are automatically skipped.</li><li>Once planning completes (status moves to <code>Pending</code>), the operator clicks <strong>Start</strong>.</li><li>A scheduled job (<code>process_bulk_agent_update</code>) picks up running updates and processes them one server at a time: <ul><li>Halt agent jobs on the server.</li><li>Run the <code>update_agent.yml</code> Ansible playbook.</li><li>Wait for the agent to respond to a ping.</li><li>On failure, optionally roll back and resume agent jobs.</li><li>On success, move to the next server.</li></ul></li><li>Final status is <code>Success</code>, <code>Partial Success</code>, or <code>Failure</code> depending on individual server outcomes.</li></ol><h2 id="doctypes" tabindex="-1">Doctypes <a class="header-anchor" href="#doctypes" aria-label="Permalink to “Doctypes”">​</a></h2><table tabindex="0"><thead><tr><th>Doctype</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Agent Update</strong></td><td>The main document. Holds configuration, source info, and the child server table.</td></tr><tr><td><strong>Agent Update Server</strong></td><td>Child table row representing a single server to update. Tracks per-server status, commits, Ansible plays, and agent health.</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to “Configuration”">​</a></h2><h3 id="general-info" tabindex="-1">General Info <a class="header-anchor" href="#general-info" aria-label="Permalink to “General Info”">​</a></h3><p>The top section shows overall status, start time, and end time.</p><h3 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to “Source”">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>repo</code></td><td>Git repository path (e.g. <code>github.com/frappe/agent</code>). Defaults to the value in <code>Press Settings</code>.</td></tr><tr><td><code>branch</code></td><td>Branch to update from. Defaults to the <code>branch</code> field in <code>Press Settings</code>.</td></tr><tr><td><code>commit_hash</code></td><td>Specific commit to deploy. Auto-populated from the branch HEAD on save if left empty.</td></tr></tbody></table><h3 id="server-types" tabindex="-1">Server Types <a class="header-anchor" href="#server-types" aria-label="Permalink to “Server Types”">​</a></h3><p>Select one or more server types to include in the update:</p><ul><li><strong>App Server</strong> (<code>Server</code>)</li><li><strong>Database Server</strong> (<code>Database Server</code>)</li><li><strong>Proxy Server</strong> (<code>Proxy Server</code>)</li></ul><p>Self-hosted servers can be excluded via the <code>exclude_self_hosted_servers</code> flag.</p><h3 id="restart-mode" tabindex="-1">Restart Mode <a class="header-anchor" href="#restart-mode" aria-label="Permalink to “Restart Mode”">​</a></h3><p>Choose which processes to restart during the update:</p><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Restart Web Workers</strong></td><td>Always required at minimum.</td></tr><tr><td><strong>Restart RQ Workers</strong></td><td>Graceful restart — waits for running tasks to finish before stopping the worker.</td></tr><tr><td><strong>Restart Redis</strong></td><td>Requires both RQ and web worker restarts to be enabled.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Most updates only need a web worker restart. Avoid restarting RQ workers unless the change requires it — a graceful RQ restart waits for in-flight tasks, which can delay the update.</p></div><h3 id="rollback-settings" tabindex="-1">Rollback Settings <a class="header-anchor" href="#rollback-settings" aria-label="Permalink to “Rollback Settings”">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Auto Rollback Changes</strong></td><td>Automatically rolls back to the previous commit on a failed update.</td></tr><tr><td><strong>Stop After Single Rollback</strong></td><td>Halts the entire run after the first rollback instead of continuing to the next server.</td></tr><tr><td><strong>Rollback to Specific Commit</strong></td><td>Rolls back all servers to a given commit instead of their individual previous commits. Useful in development environments.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Automatic rollback is only supported for agents with commits dated after 22 April 2025. Older agents must be updated manually. The planning step detects and flags these servers.</p></div><h2 id="server-status-lifecycle" tabindex="-1">Server Status Lifecycle <a class="header-anchor" href="#server-status-lifecycle" aria-label="Permalink to “Server Status Lifecycle”">​</a></h2><p>Each <code>Agent Update Server</code> row follows this state machine:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Draft → Pending → Running → Success ──→ (agent ping) → ✓ done</span></span>
<span class="line"><span>                     │                       │</span></span>
<span class="line"><span>                     ↓                       ↓ (timeout)</span></span>
<span class="line"><span>                  Failure → Rolling Back → Rolled Back → (agent ping) → ✓ done</span></span>
<span class="line"><span>                                  │                           │</span></span>
<span class="line"><span>                                  ↓                           ↓ (timeout)</span></span>
<span class="line"><span>                                Fatal                       Fatal</span></span></code></pre></div><p>Servers already on the target commit are marked <code>Skipped</code> during planning.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to “Usage”">​</a></h2><h3 id="creating-an-update" tabindex="-1">Creating an Update <a class="header-anchor" href="#creating-an-update" aria-label="Permalink to “Creating an Update”">​</a></h3><ol><li><p>Create a new <strong>Agent Update</strong> document with the desired configuration.</p><p><img src="`+o+'" alt="Configuration form"></p></li><li><p>On save, the server list is populated automatically.</p><p><img src="'+i+'" alt="Server list"></p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Review the server list before proceeding. Remove any servers you want to exclude. Servers already on the target commit will be skipped automatically.</p></div></li><li><p>Click <strong>Build Plan</strong>. This runs in the background and may take a few minutes while it fetches the current agent version from each server.</p></li><li><p>Once complete, the status changes to <code>Pending</code>.</p><p><img src="'+l+'" alt="Pending status"></p></li><li><p>Click <strong>Start</strong>.</p></li></ol><h3 id="pausing-and-resuming" tabindex="-1">Pausing and Resuming <a class="header-anchor" href="#pausing-and-resuming" aria-label="Permalink to “Pausing and Resuming”">​</a></h3><p>Click <strong>Pause</strong> to stop processing after the current server finishes. A <strong>Resume</strong> button appears to continue.</p><h3 id="test-mode" tabindex="-1">Test Mode <a class="header-anchor" href="#test-mode" aria-label="Permalink to “Test Mode”">​</a></h3><p>To update a small number of servers first and pause for verification before continuing:</p><ol><li>Enable <strong>Run on Fewer Servers and Pause</strong>.</li><li>Set the number of servers to update initially.</li></ol><p><img src="'+d+'" alt="Test mode configuration"></p><p>After the configured number of updates complete, the run pauses automatically. Click <strong>Resume</strong> to continue with the remaining servers.</p><h3 id="splitting-updates" tabindex="-1">Splitting Updates <a class="header-anchor" href="#splitting-updates" aria-label="Permalink to “Splitting Updates”">​</a></h3><p>For large fleets, sequential updates can take a long time. Splitting divides the server list into multiple independent <strong>Agent Update</strong> documents that can run in parallel.</p><ol><li><p>Build the plan first (status must be <code>Pending</code>).</p></li><li><p>Click <strong>Split Update</strong> and choose the number of batches.</p><p><img src="'+c+'" alt="Split dialog"></p></li><li><p>New Agent Update documents are created, each with a subset of servers. Run them in parallel or one at a time.</p><p><img src="'+p+'" alt="Split result — batch 1"></p><p><img src="'+h+'" alt="Split result — batch 2"></p></li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>For example, 500 servers at ~2 minutes each would take ~16 hours sequentially. Splitting into 10 batches brings that down to ~1.6 hours.</p></div><h3 id="force-continue" tabindex="-1">Force Continue <a class="header-anchor" href="#force-continue" aria-label="Permalink to “Force Continue”">​</a></h3><p>If the run ends with <code>Failure</code> or <code>Partial Success</code>, the <strong>Force Continue</strong> action resets failed servers back to <code>Pending</code> and restarts execution. This is useful after resolving an underlying issue on a specific server.</p>',43)])])}const _=t(u,[["render",g]]);export{S as __pageData,_ as default};
